import React, { useState, useEffect, useRef } from 'react';
import axios from 'axios';
import Auth from './Auth';
import './App.css';

const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000/api';

const LANGUAGES = [
  { code: 'en', speech: 'en-US', flag: '🇬🇧', name: 'English' },
  { code: 'ta', speech: 'ta-IN', flag: '🇮🇳', name: 'Tamil' },
  { code: 'hi', speech: 'hi-IN', flag: '🇮🇳', name: 'Hindi' },
  { code: 'te', speech: 'te-IN', flag: '🇮🇳', name: 'Telugu' },
  { code: 'ml', speech: 'ml-IN', flag: '🇮🇳', name: 'Malayalam' },
  { code: 'kn', speech: 'kn-IN', flag: '🇮🇳', name: 'Kannada' },
  { code: 'es', speech: 'es-ES', flag: '🇪🇸', name: 'Spanish' },
  { code: 'fr', speech: 'fr-FR', flag: '🇫🇷', name: 'French' },
  { code: 'de', speech: 'de-DE', flag: '🇩🇪', name: 'German' },
  { code: 'zh', speech: 'zh-CN', flag: '🇨🇳', name: 'Chinese' },
  { code: 'ar', speech: 'ar-SA', flag: '🇸🇦', name: 'Arabic' },
  { code: 'ja', speech: 'ja-JP', flag: '🇯🇵', name: 'Japanese' },
  { code: 'pt', speech: 'pt-BR', flag: '🇧🇷', name: 'Portuguese' },
  { code: 'ru', speech: 'ru-RU', flag: '🇷🇺', name: 'Russian' },
  { code: 'ko', speech: 'ko-KR', flag: '🇰🇷', name: 'Korean' },
  { code: 'it', speech: 'it-IT', flag: '🇮🇹', name: 'Italian' },
];

const CATEGORIES = ['General','Math','Science','History','Literature','Programming','Languages','Other'];

// ── Reusable language selector ────────────────────────────────
const LangPicker = ({ label, value, onChange, type = 'translate' }) => (
  <div className="lang-pick">
    {label && <span className="lang-pick-label">{label}</span>}
    <select value={value} onChange={e => onChange(e.target.value)}>
      {LANGUAGES.map(l => (
        <option key={type === 'speech' ? l.speech : l.code} value={type === 'speech' ? l.speech : l.code}>
          {l.flag} {l.name}
        </option>
      ))}
    </select>
  </div>
);

// ── Translation box shown inside every tab ────────────────────
const TranslateBox = ({ sourceText, onTranslated }) => {
  const [from, setFrom]       = useState('en');
  const [to, setTo]           = useState('ta');
  const [output, setOutput]   = useState('');
  const [busy, setBusy]       = useState(false);
  const [err, setErr]         = useState('');

  const run = async () => {
    const input = (sourceText || '').trim().substring(0, 500);
    if (!input) { setErr('No text to translate — add content first.'); return; }
    setBusy(true); setOutput(''); setErr('');
    try {
      // Call through our own backend to avoid CORS issues
      const res = await axios.post(`${API_URL}/translate`, { text: input, from, to });
      if (res.data?.translated) {
        setOutput(res.data.translated);
        if (onTranslated) onTranslated(res.data.translated);
      } else {
        setErr('Translation failed — try a different language pair.');
      }
    } catch (e) {
      const msg = e.response?.data?.message || 'Translation failed. Make sure your backend server is running.';
      setErr(msg);
    }
    finally { setBusy(false); }
  };

  return (
    <div className="translate-box">
      <div className="translate-box-header">
        <span className="translate-box-title">🌐 Translate</span>
        <div className="translate-box-controls">
          <LangPicker label="From" value={from} onChange={setFrom} />
          <button className="swap-mini" onClick={() => { const t = from; setFrom(to); setTo(t); setOutput(''); }}>⇄</button>
          <LangPicker label="To" value={to} onChange={setTo} />
          <button className="translate-go-btn" onClick={run} disabled={busy || !sourceText}>
            {busy ? <span className="btn-spinner"></span> : '🌐 Translate'}
          </button>
        </div>
      </div>
      {err && <p className="translate-err">⚠️ {err}</p>}
      {output && (
        <div className="translate-result">
          <div className="translate-result-header">
            <span>✅ Translation ({LANGUAGES.find(l=>l.code===to)?.flag} {LANGUAGES.find(l=>l.code===to)?.name})</span>
            <div className="translate-result-btns">
              <button onClick={() => navigator.clipboard.writeText(output)}>📋 Copy</button>
              <button onClick={() => onTranslated && onTranslated(output, true)}>➕ Add to Note</button>
            </div>
          </div>
          <p className="translate-result-text">{output}</p>
        </div>
      )}
    </div>
  );
};

export default function App() {
  // ── Core state ────────────────────────────────────────────────
  const [isAuth, setIsAuth]           = useState(false);
  const [user, setUser]               = useState(null);
  const [notes, setNotes]             = useState([]);
  const [note, setNote]               = useState({ title:'', content:'', category:'General', source:'text' });
  const [editId, setEditId]           = useState(null);
  const [filterCat, setFilterCat]     = useState('All');
  const [search, setSearch]           = useState('');
  const [loading, setLoading]         = useState(false);
  const [sidebarOpen, setSidebarOpen] = useState(true);
  const [tab, setTab]                 = useState('text');
  const [msg, setMsg]                 = useState({ type:'', text:'' });
  const [viewNote, setViewNote]       = useState(null);
  const [summary, setSummary]         = useState('');
  const [genSummary, setGenSummary]   = useState(false);
  const [isSpeaking, setIsSpeaking]   = useState(false);
  // Voice
  const [listening, setListening]     = useState(false);
  const [voiceLang, setVoiceLang]     = useState('en-US');
  const [interim, setInterim]         = useState('');
  // Video
  const [videoFile, setVideoFile]     = useState(null);
  const [videoLang, setVideoLang]     = useState('en-US');
  const [videoTranscript, setVideoTranscript] = useState('');
  const [transcribing, setTranscribing] = useState(false);
  // Screen
  const [recording, setRecording]     = useState(false);
  const [screenLang, setScreenLang]   = useState('en-US');
  const [screenTranscript, setScreenTranscript] = useState('');
  // Chat
  const [chatOpen, setChatOpen]       = useState(false);
  const [chatMsgs, setChatMsgs]       = useState([]);
  const [chatIn, setChatIn]           = useState('');
  const [thinking, setThinking]       = useState(false);

  const voiceRecogRef  = useRef(null);
  const videoRecogRef  = useRef(null);
  const screenRecogRef = useRef(null);
  const screenStream   = useRef(null);
  const videoEl        = useRef(null);
  const synthRef       = useRef(window.speechSynthesis);
  const chatEnd        = useRef(null);

  // ── Helpers ───────────────────────────────────────────────────
  const flash = (type, text) => {
    setMsg({ type, text });
    setTimeout(() => setMsg({ type:'', text:'' }), 5000);
  };

  const buildRecog = (lang, onFinal, onEnd) => {
    const SR = window.SpeechRecognition || window.webkitSpeechRecognition;
    if (!SR) { flash('error', 'Speech recognition requires Chrome or Edge browser.'); return null; }
    const r = new SR();
    r.lang = lang; r.continuous = true; r.interimResults = true;
    r.onresult = e => {
      let fin = '', int = '';
      for (let i = e.resultIndex; i < e.results.length; i++) {
        if (e.results[i].isFinal) fin += e.results[i][0].transcript + ' ';
        else int += e.results[i][0].transcript;
      }
      onFinal(fin, int);
    };
    r.onerror = e => { if (e.error !== 'no-speech') flash('error', `Speech error: ${e.error}`); };
    r.onend = onEnd || (() => {});
    return r;
  };

  const stopAll = () => {
    voiceRecogRef.current?.stop();
    videoRecogRef.current?.stop();
    screenRecogRef.current?.stop();
    screenStream.current?.getTracks().forEach(t => t.stop());
    videoEl.current?.pause();
    setListening(false); setTranscribing(false); setRecording(false); setInterim('');
  };

  // ── Auth ──────────────────────────────────────────────────────
  useEffect(() => {
    const u = localStorage.getItem('user');
    const t = localStorage.getItem('token');
    if (u && t) {
      setUser(JSON.parse(u)); setIsAuth(true);
      axios.defaults.headers.common['Authorization'] = `Bearer ${t}`;
    }
  }, []);

  const handleLogin = (u, token) => {
    setUser(u); setIsAuth(true);
    localStorage.setItem('user', JSON.stringify(u));
    localStorage.setItem('token', token);
    axios.defaults.headers.common['Authorization'] = `Bearer ${token}`;
    flash('success', `Welcome back, ${u.name}! 🎉`);
  };

  const handleLogout = () => {
    localStorage.removeItem('user'); localStorage.removeItem('token');
    delete axios.defaults.headers.common['Authorization'];
    setUser(null); setIsAuth(false); setNotes([]); resetNote();
  };

  // ── Notes CRUD ────────────────────────────────────────────────
  useEffect(() => { if (isAuth) fetchNotes(); }, [isAuth, filterCat, search]);
  useEffect(() => { chatEnd.current?.scrollIntoView({ behavior:'smooth' }); }, [chatMsgs]);

  const fetchNotes = async () => {
    try {
      setLoading(true);
      const p = new URLSearchParams();
      if (filterCat !== 'All') p.append('category', filterCat);
      if (search) p.append('search', search);
      const res = await axios.get(`${API_URL}/notes?${p}`);
      setNotes(res.data);
    } catch (e) {
      if (e.response?.status === 401) { handleLogout(); flash('error','Session expired.'); }
      else flash('error','Failed to load notes.');
    } finally { setLoading(false); }
  };

  const saveNote = async () => {
    if (!note.title || !note.content) { flash('error','Title and content are required.'); return; }
    try {
      editId ? await axios.put(`${API_URL}/notes/${editId}`, note) : await axios.post(`${API_URL}/notes`, note);
      flash('success', editId ? 'Note updated! ✅' : 'Note saved! ✅');
      resetNote(); fetchNotes();
    } catch (e) {
      if (e.response?.status === 401) { handleLogout(); flash('error','Session expired.'); }
      else flash('error','Save failed.');
    }
  };

  const deleteNote = async id => {
    if (!window.confirm('Delete this note?')) return;
    try { await axios.delete(`${API_URL}/notes/${id}`); flash('success','Note deleted.'); fetchNotes(); }
    catch { flash('error','Delete failed.'); }
  };

  const startEdit = n => {
    setNote({ title:n.title, content:n.content, category:n.category, source:n.source });
    setEditId(n._id); setSummary('');
    window.scrollTo({ top:0, behavior:'smooth' });
  };

  const resetNote = () => {
    setNote({ title:'', content:'', category:'General', source:'text' });
    setEditId(null); setSummary(''); setTab('text');
    setVideoFile(null); setVideoTranscript(''); setScreenTranscript(''); setInterim('');
    stopAll();
  };

  const downloadNote = n => {
    const a = document.createElement('a');
    a.href = URL.createObjectURL(new Blob([n.content], { type:'text/plain' }));
    a.download = `${n.title}.txt`; a.click();
  };

  // ── Smart Summary ─────────────────────────────────────────────
  const doSummary = async () => {
    if (!note.content) { flash('error','Add content first.'); return; }
    setGenSummary(true); setSummary('');
    try {
      const res = await axios.post(`${API_URL}/generate-summary`, { content: note.content });
      setSummary(res.data.summary || ''); flash('success','Summary generated! ✨');
    } catch { flash('error','Summary generation failed.'); }
    finally { setGenSummary(false); }
  };

  // ── TTS ───────────────────────────────────────────────────────
  const speak = text => {
    if (!text) return;
    if (isSpeaking) { synthRef.current.cancel(); setIsSpeaking(false); return; }
    const u = new SpeechSynthesisUtterance(text);
    u.onstart = () => setIsSpeaking(true);
    u.onend   = () => setIsSpeaking(false);
    synthRef.current.speak(u);
  };

  // ── Voice tab ─────────────────────────────────────────────────
  const startVoice = () => {
    stopAll();
    const r = buildRecog(voiceLang,
      (fin, int) => {
        if (fin) setNote(p => ({ ...p, content: p.content + fin }));
        setInterim(int);
      },
      () => { setListening(false); setInterim(''); }
    );
    if (!r) return;
    voiceRecogRef.current = r; r.start(); setListening(true);
    setNote(p => ({ ...p, source:'voice' }));
  };

  // ── Video tab ─────────────────────────────────────────────────
  const handleVideoUpload = e => {
    const f = e.target.files[0]; if (!f) return;
    setVideoFile(f); setVideoTranscript('');
    const url = URL.createObjectURL(f);
    if (videoEl.current) videoEl.current.src = url;
    flash('success', `"${f.name}" loaded — choose language and press Transcribe.`);
  };

  const startVideoTranscribe = () => {
    if (!videoEl.current || !videoFile) { flash('error','Upload a video first.'); return; }
    stopAll();
    setTranscribing(true); setVideoTranscript('');
    let acc = '';
    const r = buildRecog(videoLang,
      (fin) => {
        if (fin) { acc += fin; setVideoTranscript(acc); setNote(p => ({ ...p, content: acc })); }
      },
      () => {
        setTranscribing(false);
        if (acc) flash('success','Video transcription complete! ✅');
        else flash('error','No speech detected — make sure the video has clear audio.');
      }
    );
    if (!r) { setTranscribing(false); return; }
    videoRecogRef.current = r; r.start();
    videoEl.current.play().catch(() => {});
    videoEl.current.onended = () => { r.stop(); setTranscribing(false); };
    setNote(p => ({ ...p, source:'video' }));
  };

  // ── Screen tab ────────────────────────────────────────────────
  const startScreenRecord = async () => {
    stopAll();
    try {
      const stream = await navigator.mediaDevices.getDisplayMedia({ video:true, audio:true });
      screenStream.current = stream;
      let acc = screenTranscript;
      const r = buildRecog(screenLang,
        (fin) => {
          if (fin) { acc += fin; setScreenTranscript(acc); setNote(p => ({ ...p, content: acc })); }
        },
        () => {}
      );
      if (r) { screenRecogRef.current = r; r.start(); }
      stream.getVideoTracks()[0].onended = stopScreenRecord;
      setRecording(true);
      setNote(p => ({ ...p, source:'screen' }));
      flash('success','Recording started! Speak and your words will be transcribed live.');
    } catch(e) {
      if (e.name === 'NotAllowedError') flash('error','Screen sharing denied. Please allow it.');
      else flash('error','Screen recording failed: ' + e.message);
    }
  };

  const stopScreenRecord = () => {
    screenStream.current?.getTracks().forEach(t => t.stop());
    screenRecogRef.current?.stop();
    setRecording(false);
    flash('success','Recording stopped. Transcript saved!');
  };

  // ── AI Chat ───────────────────────────────────────────────────
  const askAI = async () => {
    if (!chatIn.trim()) return;
    setChatMsgs(p => [...p, { role:'user', content:chatIn }]);
    const q = chatIn; setChatIn(''); setThinking(true);
    try {
      const res = await axios.post(`${API_URL}/chat`, { question:q, allNotes:notes });
      setChatMsgs(p => [...p, { role:'assistant', content:res.data.response }]);
    } catch { flash('error','AI chat failed.'); }
    finally { setThinking(false); }
  };

  // ── Summary renderer ──────────────────────────────────────────
  const renderSummary = txt => txt.split('\n').map((line,i) => {
    if (line.startsWith('# '))  return <h2 key={i} className="sum-h1">{line.slice(2)}</h2>;
    if (line.startsWith('## ')) return <h3 key={i} className="sum-h2">{line.slice(3)}</h3>;
    if (line.startsWith('• '))  return <p  key={i} className="sum-bullet"><span className="sum-dot">•</span>{line.slice(2)}</p>;
    if (!line.trim())            return <div key={i} style={{height:'.4rem'}}></div>;
    return <p key={i} className="sum-text">{line}</p>;
  });

  // ── Translate-and-append helper for TranslateBox ──────────────
  const appendTranslation = (translated, append) => {
    if (append) setNote(p => ({ ...p, content: p.content + '\n\n[Translation]\n' + translated }));
  };

  if (!isAuth) return <Auth onLogin={handleLogin} />;

  /* ════════════════════════════════════════════════════════════
     RENDER
  ════════════════════════════════════════════════════════════ */
  return (
    <div className="app">

      {/* ── SIDEBAR ─────────────────────────────────────────── */}
      <aside className={`sidebar ${sidebarOpen ? 'open' : 'closed'}`}>
        <div className="sidebar-header">
          <h2 className="sidebar-title">📚 SmartNotes</h2>
          <button className="sidebar-toggle" onClick={() => setSidebarOpen(p=>!p)}>
            {sidebarOpen ? '◀' : '▶'}
          </button>
        </div>

        <div className="user-card">
          <div className="user-avi">{user?.name?.[0]?.toUpperCase()}</div>
          <div className="user-info">
            <p className="user-name">{user?.name}</p>
            <p className="user-email">{user?.email}</p>
          </div>
          <button className="logout-btn" onClick={handleLogout} title="Logout">🚪</button>
        </div>

        <input className="search-input" type="text" placeholder="🔍 Search notes…"
          value={search} onChange={e => setSearch(e.target.value)} />

        <select className="filter-select" value={filterCat} onChange={e => setFilterCat(e.target.value)}>
          <option value="All">All Categories</option>
          {CATEGORIES.map(c => <option key={c}>{c}</option>)}
        </select>

        <button className="new-btn" onClick={resetNote}>＋ New Note</button>

        <div className="notes-scroll">
          {loading ? <div className="spinner-wrap"><div className="spinner"></div></div>
            : notes.length === 0 ? <p className="empty-notes">No notes yet — create one! ☝️</p>
            : notes.map(n => (
              <div key={n._id} className={`note-card ${editId===n._id?'editing':''}`}>
                <div className="note-card-top">
                  <span className="note-card-title">{n.title}</span>
                  <span className="note-cat-badge">{n.category}</span>
                </div>
                <p className="note-card-preview">{n.content.slice(0,70)}…</p>
                <div className="note-card-actions">
                  <button onClick={() => startEdit(n)} className="na-btn na-edit">✏️</button>
                  <button onClick={() => setViewNote(n)} className="na-btn na-view">👁️</button>
                  <button onClick={() => downloadNote(n)} className="na-btn na-dl">⬇️</button>
                  <button onClick={() => deleteNote(n._id)} className="na-btn na-del">🗑️</button>
                </div>
              </div>
            ))}
        </div>
      </aside>

      {/* ── MAIN ────────────────────────────────────────────── */}
      <main className="main">
        <div className="page-header">
          <h1 className="page-title">✨ Smart Note-Taking Assistant</h1>
          <p className="page-sub">Text · Voice · Video · Screen — capture & translate in any language</p>
        </div>

        {/* Flash messages */}
        {msg.text && (
          <div className={`flash flash-${msg.type}`}>
            <span>{msg.type==='error'?'⚠️ ':''}{msg.text}</span>
            <button onClick={() => setMsg({type:'',text:''})}>✕</button>
          </div>
        )}

        {/* ── EDITOR ── */}
        <div className="editor">
          <div className="editor-topbar">
            <h2 className="editor-label">{editId ? '✏️ Editing Note' : '📝 New Note'}</h2>
            {editId && <button className="cancel-btn" onClick={resetNote}>✕ Cancel</button>}
          </div>

          <div className="editor-fields">
            <input className="title-field" type="text" placeholder="Note Title…"
              value={note.title} onChange={e => setNote(p=>({...p,title:e.target.value}))} />
            <select className="cat-field" value={note.category} onChange={e => setNote(p=>({...p,category:e.target.value}))}>
              {CATEGORIES.map(c => <option key={c}>{c}</option>)}
            </select>
          </div>

          {/* Tabs */}
          <div className="tabs">
            {[['text','✍️','Text'],['voice','🎤','Voice'],['video','🎥','Video'],['screen','🖥️','Screen']].map(([id,ico,lbl])=>(
              <button key={id} className={`tab ${tab===id?'active':''}`}
                onClick={() => { setTab(id); stopAll(); }}>
                {ico}<span className="tab-txt">{lbl}</span>
              </button>
            ))}
          </div>

          {/* ══ TEXT TAB ══════════════════════════════════════ */}
          {tab === 'text' && (
            <div className="tab-body">
              <textarea className="content-area" rows={10} placeholder="Start typing your notes here…"
                value={note.content} onChange={e => setNote(p=>({...p,content:e.target.value}))} />
              <TranslateBox sourceText={note.content} onTranslated={appendTranslation} />
            </div>
          )}

          {/* ══ VOICE TAB ═════════════════════════════════════ */}
          {tab === 'voice' && (
            <div className="tab-body">
              <div className="how-it-works">
                💡 <strong>How to use:</strong> Choose your spoken language → Press <em>Start Voice</em> → Speak clearly → Text appears live → Translate the result below.
              </div>

              <div className="control-bar">
                <LangPicker label="Speak in:" value={voiceLang} onChange={setVoiceLang} type="speech" />
                <button className={`rec-btn ${listening?'rec-active':''}`}
                  onClick={listening ? () => { voiceRecogRef.current?.stop(); setListening(false); } : startVoice}>
                  {listening ? <><span className="rec-dot"></span> Stop</> : <>🎤 Start Voice</>}
                </button>
                {listening && <span className="live-pill">🔴 LIVE</span>}
              </div>

              {interim && (
                <div className="interim-preview">
                  <span className="interim-label">Hearing:</span> <em>{interim}</em>
                </div>
              )}

              <textarea className="content-area" rows={8} placeholder="Spoken text appears here in real-time…"
                value={note.content} onChange={e => setNote(p=>({...p,content:e.target.value}))} />

              {/* ✅ Translate section in Voice tab */}
              <TranslateBox sourceText={note.content} onTranslated={appendTranslation} />
            </div>
          )}

          {/* ══ VIDEO TAB ═════════════════════════════════════ */}
          {tab === 'video' && (
            <div className="tab-body">
              <div className="how-it-works">
                💡 <strong>How to use:</strong> Upload video → Select the language spoken in it → Press <em>▶ Transcribe</em> → Audio is converted to text → Then translate below.
              </div>

              <label className="upload-zone">
                <input type="file" accept="video/*" onChange={handleVideoUpload} hidden />
                <span className="upload-ico">📹</span>
                <span className="upload-main">{videoFile ? videoFile.name : 'Click to upload video'}</span>
                <span className="upload-hint">MP4 · MOV · AVI · WebM</span>
              </label>

              {videoFile && (
                <>
                  <video ref={videoEl} className="video-player" controls
                    src={URL.createObjectURL(videoFile)} />

                  <div className="control-bar">
                    <LangPicker label="Language in video:" value={videoLang} onChange={setVideoLang} type="speech" />
                    {!transcribing
                      ? <button className="rec-btn" onClick={startVideoTranscribe}>▶ Transcribe Video</button>
                      : <button className="rec-btn rec-active" onClick={() => { videoRecogRef.current?.stop(); videoEl.current?.pause(); setTranscribing(false); }}>
                          <span className="rec-dot"></span> Stop
                        </button>}
                    {transcribing && <span className="live-pill">🔴 Transcribing…</span>}
                  </div>

                  {videoTranscript && (
                    <div className="transcript-panel">
                      <div className="transcript-panel-head">
                        <span>📝 Video Transcript</span>
                        <button onClick={() => setNote(p=>({...p, content:videoTranscript}))}>➕ Set as Note</button>
                      </div>
                      <p className="transcript-text">{videoTranscript}</p>
                    </div>
                  )}
                </>
              )}

              <textarea className="content-area" rows={6} placeholder="Transcript will appear here automatically…"
                value={note.content} onChange={e => setNote(p=>({...p,content:e.target.value}))} />

              {/* ✅ Translate section in Video tab */}
              <TranslateBox sourceText={note.content || videoTranscript} onTranslated={appendTranslation} />
            </div>
          )}

          {/* ══ SCREEN TAB ════════════════════════════════════ */}
          {tab === 'screen' && (
            <div className="tab-body">
              <div className="how-it-works">
                💡 <strong>How to use:</strong> Choose language → Start Recording → Share your screen → <strong>Speak</strong> (or play a video with audio) → Words transcribed live → Translate below.
                <br/><span style={{color:'#f59e0b'}}>⚠️ Note: Only <strong>spoken audio</strong> is transcribed, not text visible on screen.</span>
              </div>

              <div className="control-bar">
                <LangPicker label="Language spoken:" value={screenLang} onChange={setScreenLang} type="speech" />
                {!recording
                  ? <button className="rec-btn" onClick={startScreenRecord}>🖥️ Start Recording</button>
                  : <button className="rec-btn rec-active" onClick={stopScreenRecord}>
                      <span className="rec-dot"></span> Stop Recording
                    </button>}
                {recording && <span className="live-pill">🔴 RECORDING</span>}
              </div>

              {screenTranscript && (
                <div className="transcript-panel">
                  <div className="transcript-panel-head">
                    <span>📝 Live Transcript</span>
                    <button onClick={() => setNote(p=>({...p, content:screenTranscript}))}>➕ Set as Note</button>
                    <button onClick={() => setScreenTranscript('')}>🗑️ Clear</button>
                  </div>
                  <p className="transcript-text">{screenTranscript}</p>
                </div>
              )}

              <textarea className="content-area" rows={8} placeholder="Live transcript appears here as you speak during recording…"
                value={note.content} onChange={e => setNote(p=>({...p,content:e.target.value}))} />

              {/* ✅ Translate section in Screen tab */}
              <TranslateBox sourceText={note.content || screenTranscript} onTranslated={appendTranslation} />
            </div>
          )}

          {/* ── Bottom action bar ── */}
          <div className="action-bar">
            <button className="action-btn" onClick={() => speak(note.content)} disabled={!note.content}>
              {isSpeaking ? '⏹ Stop' : '🔊 Read Aloud'}
            </button>
            <button className="action-btn" onClick={doSummary} disabled={!note.content || genSummary}>
              {genSummary ? <><span className="btn-spinner"></span> Generating…</> : '✨ Smart Summary'}
            </button>
            <button className="action-btn action-save" onClick={saveNote}>
              💾 {editId ? 'Update Note' : 'Save Note'}
            </button>
          </div>

          {/* ── Summary panel ── */}
          {summary && (
            <div className="summary-panel">
              <div className="summary-head">
                <h3>✨ Smart Summary</h3>
                <div className="summary-head-btns">
                  <button onClick={() => setNote(p=>({...p,content:summary}))}>➕ Use as Note</button>
                  <button onClick={() => speak(summary)}>🔊 Read</button>
                  <button onClick={() => navigator.clipboard.writeText(summary)}>📋 Copy</button>
                  <button onClick={() => setSummary('')}>✕</button>
                </div>
              </div>
              <div className="summary-body">{renderSummary(summary)}</div>
              {/* ✅ Translate summary too! */}
              <div style={{padding:'0 1.25rem 1.25rem'}}>
                <TranslateBox sourceText={summary} onTranslated={(t,add) => { if(add) setNote(p=>({...p,content:p.content+'\n\n'+t})); }} />
              </div>
            </div>
          )}
        </div>

        {/* Chat button */}
        <button className="chat-fab" onClick={() => setChatOpen(p=>!p)}>💬 AI Assistant</button>

        {/* Chat panel */}
        {chatOpen && (
          <div className="chat-panel">
            <div className="chat-head">
              <span>🤖 AI Assistant</span>
              <button onClick={() => setChatOpen(false)}>✕</button>
            </div>
            <div className="chat-body">
              {chatMsgs.length === 0
                ? <div className="chat-empty">
                    <p>👋 Ask me about your notes!</p>
                    {['How many notes?','What categories?','Summarize my notes'].map(s=>(
                      <button key={s} className="chat-suggestion" onClick={()=>setChatIn(s)}>{s}</button>
                    ))}
                  </div>
                : chatMsgs.map((m,i)=>(
                    <div key={i} className={`chat-msg ${m.role}`}>
                      <div className="chat-bubble">{m.content}</div>
                    </div>
                  ))}
              {thinking && <div className="chat-msg assistant"><div className="chat-bubble"><div className="dots"><span/><span/><span/></div></div></div>}
              <div ref={chatEnd}/>
            </div>
            <div className="chat-foot">
              <input placeholder="Ask about your notes…" value={chatIn}
                onChange={e=>setChatIn(e.target.value)} onKeyPress={e=>e.key==='Enter'&&askAI()} />
              <button onClick={askAI} disabled={!chatIn.trim()}>➤</button>
            </div>
          </div>
        )}
      </main>

      {/* ── VIEW NOTE MODAL ── */}
      {viewNote && (
        <div className="overlay" onClick={()=>setViewNote(null)}>
          <div className="modal" onClick={e=>e.stopPropagation()}>
            <div className="modal-head">
              <h2>{viewNote.title}</h2>
              <button onClick={()=>setViewNote(null)}>✕</button>
            </div>
            <div className="modal-body">
              <div className="modal-badges">
                <span className="badge">{viewNote.category}</span>
                <span className="badge badge-src">{viewNote.source}</span>
              </div>
              <div className="modal-content">{viewNote.content}</div>
              {/* ✅ Translate note from modal too */}
              <TranslateBox sourceText={viewNote.content} onTranslated={(t,add)=>{if(add){setNote(p=>({...p,content:t}));setViewNote(null);flash('success','Translation added as new note content!');}}} />
            </div>
            <div className="modal-foot">
              <button onClick={()=>speak(viewNote.content)}>🔊 Read</button>
              <button onClick={()=>downloadNote(viewNote)}>⬇️ Download</button>
              <button onClick={()=>{startEdit(viewNote);setViewNote(null);}}>✏️ Edit</button>
              <button className="del-btn" onClick={()=>{deleteNote(viewNote._id);setViewNote(null);}}>🗑️ Delete</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
